  ('dietitian-moex-00593', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據學校餐廳廚房員生消費合作社衛生管理辦法，下列敘述何者錯誤？', '["領有營養師執業執照者可為餐飲衛生業務之督導人員", "學校餐飲從業人員應於每學年開學前2週內或新進用前接受健康檢查，合格者始得從事餐飲工作", "學校餐飲從業人員每學年應參加衛生（健康飲食）講習至少8小時", "學校採盒餐供餐者，應保留盒餐樣本至少1份，標示日期、餐別，置於攝氏7度以下，冷藏保 存24小時，以備查驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "6300cf2ce819", "answer_pdf_sha1": "cc22ae4e4f64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
